/** Immediately switch to a different input stream.
 * @param input_file A readable stream.
 * @param eckit_sql_scanner The scanner object.
 * @note This function does not reset the start condition to @c INITIAL .
 */
/* %if-c-only */
    void eckit_sql_restart  (FILE * input_file , eckit_sql_scan_t eckit_sql_scanner)
/* %endif */
/* %if-c++-only */
/* %endif */
{
    struct eckit_sql_guts_t * eckit_sql_g = (struct eckit_sql_guts_t*)eckit_sql_scanner;

	if ( ! YY_CURRENT_BUFFER ){
        eckit_sql_ensure_buffer_stack (eckit_sql_scanner);
		YY_CURRENT_BUFFER_LVALUE =
            eckit_sql__create_buffer( eckit_sql_in, YY_BUF_SIZE , eckit_sql_scanner);
	}

	eckit_sql__init_buffer( YY_CURRENT_BUFFER, input_file , eckit_sql_scanner);
	eckit_sql__load_buffer_state( eckit_sql_scanner );
}

/* %if-c++-only */
/* %endif */

/** Switch to a different input buffer.
 * @param new_buffer The new input buffer.
 * @param eckit_sql_scanner The scanner object.
 */
/* %if-c-only */
    void eckit_sql__switch_to_buffer  (YY_BUFFER_STATE  new_buffer , eckit_sql_scan_t eckit_sql_scanner)
/* %endif */
/* %if-c++-only */
/* %endif */
{
    struct eckit_sql_guts_t * eckit_sql_g = (struct eckit_sql_guts_t*)eckit_sql_scanner;

	/* TODO. We should be able to replace this entire function body
	 * with
	 *		eckit_sql_pop_buffer_state();
	 *		eckit_sql_push_buffer_state(new_buffer);
     */
	eckit_sql_ensure_buffer_stack (eckit_sql_scanner);
	if ( YY_CURRENT_BUFFER == new_buffer )
		return;

	if ( YY_CURRENT_BUFFER )
		{
		/* Flush out information for old buffer. */
		*eckit_sql_g->eckit_sql__c_buf_p = eckit_sql_g->eckit_sql__hold_char;
		YY_CURRENT_BUFFER_LVALUE->eckit_sql__buf_pos = eckit_sql_g->eckit_sql__c_buf_p;
		YY_CURRENT_BUFFER_LVALUE->eckit_sql__n_chars = eckit_sql_g->eckit_sql__n_chars;
		}

	YY_CURRENT_BUFFER_LVALUE = new_buffer;
	eckit_sql__load_buffer_state( eckit_sql_scanner );

	/* We don't actually know whether we did this switch during
	 * EOF (eckit_sql_wrap()) processing, but the only time this flag
	 * is looked at is after eckit_sql_wrap() is called, so it's safe
	 * to go ahead and always set it.
	 */
	eckit_sql_g->eckit_sql__did_buffer_switch_on_eof = 1;
}

/* %if-c-only */
static void eckit_sql__load_buffer_state  (eckit_sql_scan_t eckit_sql_scanner)
/* %endif */
/* %if-c++-only */
/* %endif */
{
    struct eckit_sql_guts_t * eckit_sql_g = (struct eckit_sql_guts_t*)eckit_sql_scanner;
	eckit_sql_g->eckit_sql__n_chars = YY_CURRENT_BUFFER_LVALUE->eckit_sql__n_chars;
	eckit_sql_g->eckit_sql_text_ptr = eckit_sql_g->eckit_sql__c_buf_p = YY_CURRENT_BUFFER_LVALUE->eckit_sql__buf_pos;
/* %if-c-only */
	eckit_sql_in = YY_CURRENT_BUFFER_LVALUE->eckit_sql__input_file;
/* %endif */
/* %if-c++-only */
/* %endif */
	eckit_sql_g->eckit_sql__hold_char = *eckit_sql_g->eckit_sql__c_buf_p;
}

/** Allocate and initialize an input buffer state.
 * @param file A readable stream.
 * @param size The character buffer size in bytes. When in doubt, use @c YY_BUF_SIZE.
 * @param eckit_sql_scanner The scanner object.
 * @return the allocated buffer state.
 */
/* %if-c-only */
    YY_BUFFER_STATE eckit_sql__create_buffer  (FILE * file, int  size , eckit_sql_scan_t eckit_sql_scanner)
/* %endif */
/* %if-c++-only */
/* %endif */
{
	YY_BUFFER_STATE b;
    
	b = (YY_BUFFER_STATE) eckit_sql_alloc( sizeof( struct eckit_sql__buffer_state ) , eckit_sql_scanner );
	if ( ! b )
		YY_FATAL_ERROR( "out of dynamic memory in eckit_sql__create_buffer()" );

	b->eckit_sql__buf_size = size;

	/* eckit_sql__ch_buf has to be 2 characters longer than the size given because
	 * we need to put in 2 end-of-buffer characters.
	 */
	b->eckit_sql__ch_buf = (char *) eckit_sql_alloc( (eckit_sql__size_t) (b->eckit_sql__buf_size + 2) , eckit_sql_scanner );
	if ( ! b->eckit_sql__ch_buf )
		YY_FATAL_ERROR( "out of dynamic memory in eckit_sql__create_buffer()" );

	b->eckit_sql__is_our_buffer = 1;

	eckit_sql__init_buffer( b, file , eckit_sql_scanner);

	return b;
}

