/* %endif */

/** Destroy the buffer.
 * @param b a buffer created with eckit_sql__create_buffer()
 * @param eckit_sql_scanner The scanner object.
 */
/* %if-c-only */
    void eckit_sql__delete_buffer (YY_BUFFER_STATE  b , eckit_sql_scan_t eckit_sql_scanner)
/* %endif */
/* %if-c++-only */
/* %endif */
{
    struct eckit_sql_guts_t * eckit_sql_g = (struct eckit_sql_guts_t*)eckit_sql_scanner;

	if ( ! b )
		return;

	if ( b == YY_CURRENT_BUFFER ) /* Not sure if we should pop here. */
		YY_CURRENT_BUFFER_LVALUE = (YY_BUFFER_STATE) 0;

	if ( b->eckit_sql__is_our_buffer )
		eckit_sql_free( (void *) b->eckit_sql__ch_buf , eckit_sql_scanner );

	eckit_sql_free( (void *) b , eckit_sql_scanner );
}

/* Initializes or reinitializes a buffer.
 * This function is sometimes called more than once on the same buffer,
 * such as during a eckit_sql_restart() or at EOF.
 */
/* %if-c-only */
    static void eckit_sql__init_buffer  (YY_BUFFER_STATE  b, FILE * file , eckit_sql_scan_t eckit_sql_scanner)
/* %endif */
/* %if-c++-only */
/* %endif */

{
	int oerrno = errno;
    struct eckit_sql_guts_t * eckit_sql_g = (struct eckit_sql_guts_t*)eckit_sql_scanner;

	eckit_sql__flush_buffer( b , eckit_sql_scanner);

/* %if-c-only */
	b->eckit_sql__input_file = file;
/* %endif */
/* %if-c++-only */
/* %endif */
	b->eckit_sql__fill_buffer = 1;

    /* If b is the current buffer, then eckit_sql__init_buffer was _probably_
     * called from eckit_sql_restart() or through eckit_sql__get_next_buffer.
     * In that case, we don't want to reset the lineno or column.
     */
    if (b != YY_CURRENT_BUFFER){
        b->eckit_sql__bs_lineno = 1;
        b->eckit_sql__bs_column = 0;
    }

/* %if-c-only */

        b->eckit_sql__is_interactive = file ? (isatty( fileno(file) ) > 0) : 0;
    
/* %endif */
/* %if-c++-only */
/* %endif */
	errno = oerrno;
}

/** Discard all buffered characters. On the next scan, YY_INPUT will be called.
 * @param b the buffer state to be flushed, usually @c YY_CURRENT_BUFFER.
 * @param eckit_sql_scanner The scanner object.
 */
/* %if-c-only */
    void eckit_sql__flush_buffer (YY_BUFFER_STATE  b , eckit_sql_scan_t eckit_sql_scanner)
/* %endif */
/* %if-c++-only */
/* %endif */
{
    struct eckit_sql_guts_t * eckit_sql_g = (struct eckit_sql_guts_t*)eckit_sql_scanner;
	if ( ! b )
		return;

	b->eckit_sql__n_chars = 0;

	/* We always need two end-of-buffer characters.  The first causes
	 * a transition to the end-of-buffer state.  The second causes
	 * a jam in that state.
	 */
	b->eckit_sql__ch_buf[0] = YY_END_OF_BUFFER_CHAR;
	b->eckit_sql__ch_buf[1] = YY_END_OF_BUFFER_CHAR;

	b->eckit_sql__buf_pos = &b->eckit_sql__ch_buf[0];

	b->eckit_sql__at_bol = 1;
	b->eckit_sql__buffer_status = YY_BUFFER_NEW;

	if ( b == YY_CURRENT_BUFFER )
		eckit_sql__load_buffer_state( eckit_sql_scanner );
}

/* %if-c-or-c++ */
/** Pushes the new state onto the stack. The new state becomes
 *  the current state. This function will allocate the stack
 *  if necessary.
 *  @param new_buffer The new state.
 *  @param eckit_sql_scanner The scanner object.
 */
/* %if-c-only */
void eckit_sql_push_buffer_state (YY_BUFFER_STATE new_buffer , eckit_sql_scan_t eckit_sql_scanner)
/* %endif */
/* %if-c++-only */
/* %endif */
{
    struct eckit_sql_guts_t * eckit_sql_g = (struct eckit_sql_guts_t*)eckit_sql_scanner;
	if (new_buffer == NULL)
		return;

	eckit_sql_ensure_buffer_stack(eckit_sql_scanner);

	/* This block is copied from eckit_sql__switch_to_buffer. */
	if ( YY_CURRENT_BUFFER )
		{
		/* Flush out information for old buffer. */
		*eckit_sql_g->eckit_sql__c_buf_p = eckit_sql_g->eckit_sql__hold_char;
		YY_CURRENT_BUFFER_LVALUE->eckit_sql__buf_pos = eckit_sql_g->eckit_sql__c_buf_p;
		YY_CURRENT_BUFFER_LVALUE->eckit_sql__n_chars = eckit_sql_g->eckit_sql__n_chars;
		}

	/* Only push if top exists. Otherwise, replace top. */
	if (YY_CURRENT_BUFFER)
		eckit_sql_g->eckit_sql__buffer_stack_top++;
	YY_CURRENT_BUFFER_LVALUE = new_buffer;

	/* copied from eckit_sql__switch_to_buffer. */
	eckit_sql__load_buffer_state( eckit_sql_scanner );
	eckit_sql_g->eckit_sql__did_buffer_switch_on_eof = 1;
}
/* %endif */

/* %if-c-or-c++ */
/** Removes and deletes the top of the stack, if present.
 *  The next element becomes the new top.
 *  @param eckit_sql_scanner The scanner object.
 */
/* %if-c-only */
void eckit_sql_pop_buffer_state (eckit_sql_scan_t eckit_sql_scanner)
/* %endif */
/* %if-c++-only */
/* %endif */
{
    struct eckit_sql_guts_t * eckit_sql_g = (struct eckit_sql_guts_t*)eckit_sql_scanner;
	if (!YY_CURRENT_BUFFER)
		return;

	eckit_sql__delete_buffer(YY_CURRENT_BUFFER , eckit_sql_scanner);
	YY_CURRENT_BUFFER_LVALUE = NULL;
	if (eckit_sql_g->eckit_sql__buffer_stack_top > 0)
		--eckit_sql_g->eckit_sql__buffer_stack_top;

	if (YY_CURRENT_BUFFER) {
		eckit_sql__load_buffer_state( eckit_sql_scanner );
		eckit_sql_g->eckit_sql__did_buffer_switch_on_eof = 1;
	}
}
